-- Seed all WriteOne worksheet metadata used by the app and AI grading.
-- Safe to rerun: rows are upserted by code.
on conflict (code) do update set
  level = excluded.level,
  title = excluded.title,
  topic_jp = excluded.topic_jp,
  topic_en = excluded.topic_en,
  word_count_min = excluded.word_count_min,
  word_count_max = excluded.word_count_max,
  structure = excluded.structure,
  tips = excluded.tips,
  pdf_url = excluded.pdf_url,
  sort_order = excluded.sort_order,
  is_published = excluded.is_published;
